import React, { useState } from "react";
import Navbar from "../auth/Navbar";
import axios from "axios";


function Register()
{

    const [registerInput, setRegister] = useState({
        name: "",
        email: "",
        password: "",
    });

    const handleInput = (e) =>
    {
        e.persist();
        setRegister({
            ...registerInput,
            [e.target.name]: e.target.value,
        });
    }

    const RegisterSubmit = (e) =>
    {
        e.preventDefault();
        console.log(registerInput);

        const data = {
            name: registerInput.name,
            email: registerInput.email,
            password: registerInput.password,
        }


        axios.post('/sanctum/csrf-cookie').then(response => 
        {
            axios.post('http://127.0.0.1:8000/api/register', data).then(res => 
            {
                if (res.data.status === 200)
                {

                }
                else
                {
                    setRegister
                        ({ ...registerInput, error_list: res.data.validation_errors });
                }
            });
        });

    }


    return (
        <div>
            <Navbar />

            <div className="container py-5">
                <div className="row justify-content-center">
                    <div className="col-xl-6">
                        <div className="card">
                            <div className="card-body">
                                <h4>Register</h4>
                            </div>
                            <div className="card-body">
                                <form onSubmit={RegisterSubmit}>
                                    <div className="form-group mb-3">
                                        <label>Name</label>
                                        <input type="" name="name" onChange={handleInput} value={registerInput.name} className="form-control" />
                                    </div>

                                    <div className="form-group mb-3">
                                        <label>Email</label>
                                        <input type="" name="email" onChange={handleInput} value={registerInput.email} className="form-control" />
                                    </div>

                                    <div>
                                        <div className="form-group mb-3">
                                            <label>Password</label>
                                            <input type="" name="password" onChange={handleInput} value={registerInput.password} className="form-control" />
                                        </div>
                                    </div>

                                    <div className="form-group mb-3">
                                        <button type="submit" className="btn btn-primary">Register"</button>
                                    </div>
                                </form>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default Register;
